const BATCH_SIZE = 100;
const xmlString = $json.data;

const locRegex = /<loc>([^<]+)<\/loc>/g;
const urls = [];
let match;

function normalizeUrl(u) {
  const url = (u || "").trim();

  // Only touch http/https URLs
  if (!/^https?:\/\//i.test(url)) return url;

  // Split off query/hash (preserve them)
  const splitIndex = url.search(/[?#]/);
  const base = splitIndex === -1 ? url : url.slice(0, splitIndex);
  const suffix = splitIndex === -1 ? "" : url.slice(splitIndex);

  // If already ends with slash on the base part, keep it
  if (base.endsWith("/")) return base + suffix;

  // If it's just a domain (no path), add slash
  // e.g. https://example.com  -> https://example.com/
  const afterProtocol = base.replace(/^https?:\/\//i, "");
  const firstSlash = afterProtocol.indexOf("/");
  if (firstSlash === -1) return base + "/" + suffix;

  // Check last path segment for a real file extension
  // (common pattern: .xml, .html, .pdf, .jpg, etc.)
  const path = base.slice(base.indexOf("/", base.indexOf("//") + 2)); // includes leading '/'
  const lastSegment = path.split("/").pop() || "";

  const hasFileExtension = /\.[a-z0-9]{1,6}$/i.test(lastSegment);
  if (hasFileExtension) return base + suffix;

  // Otherwise, looks like a "page" => add trailing slash
  return base + "/" + suffix;
}

while ((match = locRegex.exec(xmlString)) !== null) {
  urls.push(normalizeUrl(match[1]));
}

const batches = [];
for (let i = 0; i < urls.length; i += BATCH_SIZE) {
  const batch = urls.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      urls: batch,
      batchNumber: Math.floor(i / BATCH_SIZE) + 1,
      totalBatches: Math.ceil(urls.length / BATCH_SIZE),
    },
  });
}

return batches;

