  Boolean((() => {
    const inputs = $('Set Inputs').first().json || {};

    const normalizeHost = (s) => {
      s = ('' + (s || '')).trim().toLowerCase();
      if (!s) return '';
      s = s.replace(/^https?:\/\//, '');
      s = s.split('#')[0].split('?')[0];
      let host = (s.split('/')[0] || '').replace(/\.$/, '');
      if (host.startsWith('www.')) host = host.slice(4);
      return host;
    };

    const parseHosts = (v) =>
      ('' + (v || ''))
        .split(',')
        .map(x => normalizeHost(x))
        .filter(Boolean);

    const srcHost = normalizeHost($json.Source);
    if (!srcHost) return false;

    const allowedSub = parseHosts(inputs.allowedSubdomains);
    const blockedSub = parseHosts(inputs.blockedSubdomains);

    // 1) allowedSubdomains is a HARD allowlist if set
    if (allowedSub.length > 0 && !allowedSub.includes(srcHost)) return false;

    // 2) blocklist always applies (override deny)
    if (blockedSub.length > 0 && blockedSub.includes(srcHost)) return false;

    return true;
  })())
}}

