    const src = ('' + ($json.Source || '')).toLowerCase();
    if (!src) return false;

    const parse = v =>
      ('' + (v || ''))
        .split(',')
        .map(s => s.trim().toLowerCase())
        .filter(Boolean);

    const allowed = parse($('Set Inputs').first().json.allowedSections);
    const blocked = parse($('Set Inputs').first().json.blockedSections);

    // Match section as:
    //  - "/section/" anywhere (directory)
    //  - "/section-<something>/" anywhere (hyphenated directory)
    // NOT filenames like "/section-thing.htm"
    const matches = (section) => {
      const re = new RegExp(`/${section}(?:/|-[^/]+/)`);
      return re.test(src);
    };

    // 1) blocklist wins
    if (blocked.some(matches)) return false;

    // 2) no allowlist => allow
    if (allowed.length === 0) return true;

    // 3) otherwise must match allowlist
    return allowed.some(matches);
  })())
}}
